renderScript:
function(wrap, spec) {
  var rows = spec.rows || [];
  if (!rows.length) {
    wrap.style.cssText = 'padding:16px;color:#888;font-size:13px;';
    wrap.textContent = 'Swimlane: no data — need columns time, actor, label (and optional message, category, value, event_id, cause_id).';
    return;
  }

  var parseTime = function(v) {
    if (v == null) return null;
    if (typeof v === 'number') return v;
    var s = String(v).trim();
    var m = s.match(/^(\d{1,2}):(\d{2})(?::(\d{2}))?$/);
    if (m) return (+m[1]) * 3600 + (+m[2]) * 60 + (+(m[3] || 0));
    var d = new Date(s);
    if (!isNaN(d)) return d.getTime();
    var n = +s;
    return isNaN(n) ? null : n;
  };

  var events = rows.map(function(r, i) {
    return {
      id: r.event_id != null ? String(r.event_id) : 'e' + i,
      causeId: r.cause_id != null ? String(r.cause_id) : null,
      timeRaw: r.time,
      time: parseTime(r.time),
      actor: String(r.actor || 'Unknown'),
      label: String(r.label || ''),
      message: String(r.message || ''),
      category: r.category ? String(r.category) : '',
      value: +(r.value || 1)
    };
  }).filter(function(e) { return e.time != null && e.actor; });

  if (!events.length) {
    wrap.style.cssText = 'padding:16px;color:#888;';
    wrap.textContent = 'Swimlane: no valid events after parsing.';
    return;
  }

  var lanes = [];
  var laneSet = {};
  (spec.actors || []).forEach(function(a) { if (!laneSet[a]) { laneSet[a] = 1; lanes.push(a); } });
  events.forEach(function(e) { if (!laneSet[e.actor]) { laneSet[e.actor] = 1; lanes.push(e.actor); } });

  var cats = [];
  events.forEach(function(e) { if (e.category && cats.indexOf(e.category) < 0) cats.push(e.category); });
  var PAL = ['#5470c6', '#ee6666', '#91cc75', '#fac858', '#73c0de', '#fc8452', '#9a60b4', '#3ba272', '#ea7ccc'];
  var cColor = function(c) { var i = cats.indexOf(c); return i < 0 ? '#5470c6' : PAL[i % PAL.length]; };

  var isClockTime = events.every(function(e) {
    return typeof e.timeRaw === 'string' && /^\d{1,2}:\d{2}/.test(e.timeRaw.trim());
  });

  var tMin = d3.min(events, function(e) { return e.time; });
  var tMax = d3.max(events, function(e) { return e.time; });
  var tPad = (tMax - tMin) * 0.04 || 1;
  tMin -= tPad; tMax += tPad;

  var fmtTime = function(t) {
    if (isClockTime) {
      var h = Math.floor(t / 3600), m = Math.floor((t % 3600) / 60);
      return (h < 10 ? '0' : '') + h + ':' + (m < 10 ? '0' : '') + m;
    }
    var d = new Date(t);
    var range = tMax - tMin;
    if (range < 24 * 3600 * 1000) return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    if (range < 31 * 24 * 3600 * 1000) return d.toLocaleString([], { month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit' });
    return d.toLocaleDateString();
  };

  var visible = {};
  cats.forEach(function(c) { visible[c] = true; });

  wrap.innerHTML = '';
  wrap.style.cssText = 'user-select:none;max-height:1000px;overflow:auto;font-family:system-ui,sans-serif;';

  var hdr = document.createElement('div');
  hdr.style.cssText = 'position:sticky;top:0;z-index:5;background:var(--bg,#fff);padding:4px 0 6px;';
  wrap.appendChild(hdr);
  if (spec.title) {
    var ttl = document.createElement('div');
    ttl.style.cssText = 'text-align:center;font-size:13px;font-weight:500;color:var(--text,#333);margin-bottom:4px;';
    ttl.textContent = spec.title;
    hdr.appendChild(ttl);
  }
  var hint = document.createElement('div');
  hint.style.cssText = 'text-align:center;font-size:10px;color:var(--text3,#999);margin-bottom:4px;';
  hint.textContent = 'Hover events for full message · Scroll to zoom · Drag to pan · Double-click to reset';
  hdr.appendChild(hint);

  var legendItems = [];
  if (cats.length > 1) {
    var lgd = document.createElement('div');
    lgd.style.cssText = 'display:flex;flex-wrap:wrap;justify-content:center;gap:4px 12px;padding:0 8px;font-size:11px;';
    cats.forEach(function(cat) {
      var itm = document.createElement('span');
      itm.style.cssText = 'cursor:pointer;display:inline-flex;align-items:center;gap:4px;color:var(--text2,#666);';
      var sw = document.createElement('span');
      sw.style.cssText = 'display:inline-block;width:10px;height:10px;border-radius:50%;background:' + cColor(cat) + ';';
      itm.appendChild(sw);
      itm.appendChild(document.createTextNode(cat));
      itm.addEventListener('click', function() { visible[cat] = !visible[cat]; render(); });
      lgd.appendChild(itm);
      legendItems.push({ el: itm, cat: cat });
    });
    hdr.appendChild(lgd);
  }

  var host = document.createElement('div');
  host.style.cssText = 'overflow-x:auto;';
  wrap.appendChild(host);

  var tip = document.createElement('div');
  tip.style.cssText = 'position:fixed;display:none;background:rgba(20,20,28,0.95);color:#fff;padding:8px 10px;border-radius:6px;font-size:12px;max-width:360px;line-height:1.45;pointer-events:none;z-index:1000;box-shadow:0 4px 14px rgba(0,0,0,0.25);white-space:normal;word-wrap:break-word;';
  document.body.appendChild(tip);

  var PAD_L = 150, PAD_R = 60, PAD_T = 14, PAD_B = 50;
  var LANE_H = 56;
  var W = Math.max(720, (wrap.clientWidth || wrap.offsetWidth || 900) - 32);
  var H = PAD_T + lanes.length * LANE_H + PAD_B;

  var hostSvg = null;

  var escapeHtml = function(s) {
    return String(s).replace(/[&<>"']/g, function(c) {
      return { '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' }[c];
    });
  };

  var render = function() {
    legendItems.forEach(function(it) {
      var on = !!visible[it.cat];
      it.el.style.opacity = on ? '1' : '0.35';
      it.el.style.textDecoration = on ? 'none' : 'line-through';
    });

    var visEvents = events.filter(function(e) { return !e.category || visible[e.category]; });

    if (hostSvg) hostSvg.remove();
    var svg = d3.select(host).append('svg')
      .attr('width', W).attr('height', H)
      .style('display', 'block').style('background', 'var(--bg,#fff)');
    hostSvg = svg.node();

    var defs = svg.append('defs');
    defs.append('marker')
      .attr('id', 'swim-arrow').attr('viewBox', '0 -5 10 10')
      .attr('refX', 8).attr('refY', 0)
      .attr('markerWidth', 7).attr('markerHeight', 7).attr('orient', 'auto')
      .append('path').attr('d', 'M0,-5L10,0L0,5').attr('fill', '#888');

    var xScale = d3.scaleLinear().domain([tMin, tMax]).range([PAD_L, W - PAD_R]);
    var root = svg.append('g');

    lanes.forEach(function(a, i) {
      var laneTop = PAD_T + i * LANE_H;
      var laneMid = laneTop + LANE_H / 2;
      if (i % 2 === 0) {
        root.append('rect')
          .attr('x', PAD_L).attr('y', laneTop)
          .attr('width', W - PAD_L - PAD_R).attr('height', LANE_H)
          .attr('fill', 'var(--bg2,#f7f6f2)').attr('opacity', 0.45);
      }
      root.append('line')
        .attr('x1', PAD_L).attr('y1', laneMid).attr('x2', W - PAD_R).attr('y2', laneMid)
        .attr('stroke', 'var(--border,#dcdcdc)').attr('stroke-width', 1).attr('stroke-dasharray', '3,4');
      var rawLbl = a;
      var shortLbl = rawLbl.length > 22 ? rawLbl.slice(0, 21) + '…' : rawLbl;
      var lblEl = root.append('text')
        .attr('x', PAD_L - 10).attr('y', laneMid + 4).attr('text-anchor', 'end')
        .attr('font-size', 12).attr('font-weight', 600).attr('fill', 'var(--text,#444)')
        .text(shortLbl);
      if (rawLbl !== shortLbl) lblEl.append('title').text(rawLbl);
    });

    var axisY = PAD_T + lanes.length * LANE_H + 10;
    root.append('line')
      .attr('x1', PAD_L).attr('y1', axisY).attr('x2', W - PAD_R).attr('y2', axisY)
      .attr('stroke', 'var(--border2,#aaa)').attr('stroke-width', 1);

    var ticks;
    if (isClockTime) {
      var step = (tMax - tMin) > 8 * 3600 ? 3600 : (tMax - tMin) > 2 * 3600 ? 1800 : 600;
      ticks = [];
      for (var t = Math.ceil(tMin / step) * step; t <= tMax; t += step) ticks.push(t);
    } else {
      ticks = xScale.ticks(Math.min(10, Math.floor((W - PAD_L - PAD_R) / 90)));
    }
    ticks.forEach(function(tk) {
      var x = xScale(tk);
      if (x < PAD_L - 1 || x > W - PAD_R + 1) return;
      root.append('line')
        .attr('x1', x).attr('y1', PAD_T).attr('x2', x).attr('y2', axisY)
        .attr('stroke', 'var(--border,#eee)').attr('stroke-width', 1);
      root.append('text')
        .attr('x', x).attr('y', axisY + 16).attr('text-anchor', 'middle')
        .attr('font-size', 10).attr('fill', 'var(--text3,#888)')
        .text(fmtTime(tk));
    });

    var laneIdx = {};
    lanes.forEach(function(a, i) { laneIdx[a] = i; });

    visEvents.forEach(function(e) {
      e._x = xScale(e.time);
      e._yBase = PAD_T + laneIdx[e.actor] * LANE_H + LANE_H / 2;
      e._yOff = 0;
    });
    var byLane = {};
    lanes.forEach(function(a) { byLane[a] = []; });
    visEvents.forEach(function(e) { if (byLane[e.actor]) byLane[e.actor].push(e); });
    Object.keys(byLane).forEach(function(a) {
      var arr = byLane[a].sort(function(p, q) { return p._x - q._x; });
      for (var i = 1; i < arr.length; i++) {
        if (arr[i]._x - arr[i - 1]._x < 16) {
          var prevOff = arr[i - 1]._yOff;
          arr[i]._yOff = prevOff > 0 ? -10 : prevOff < 0 ? 0 : 10;
        }
      }
    });

    var idIdx = {};
    visEvents.forEach(function(e) { idIdx[e.id] = e; });
    visEvents.forEach(function(e) {
      if (!e.causeId || !idIdx[e.causeId]) return;
      var src = idIdx[e.causeId];
      var sx = src._x, sy = src._yBase + src._yOff;
      var tx2 = e._x, ty = e._yBase + e._yOff;
      var mx = (sx + tx2) / 2;
      var d = 'M ' + sx + ' ' + sy + ' C ' + mx + ' ' + sy + ', ' + mx + ' ' + ty + ', ' + tx2 + ' ' + ty;
      root.append('path')
        .attr('d', d).attr('fill', 'none')
        .attr('stroke', '#888').attr('stroke-width', 1.3)
        .attr('stroke-dasharray', '4,3').attr('opacity', 0.55)
        .attr('marker-end', 'url(#swim-arrow)');
    });

    var vMax = d3.max(visEvents, function(e) { return e.value; }) || 1;
    var rScale = d3.scaleSqrt().domain([0, vMax]).range([4, 11]);

    var markerLayer = root.append('g');
    visEvents.forEach(function(e) {
      var x = e._x, y = e._yBase + e._yOff;
      var r = rScale(e.value);
      var col = e.category ? cColor(e.category) : '#5470c6';
      var g = markerLayer.append('g').style('cursor', 'pointer');
      g.append('circle').attr('cx', x).attr('cy', y).attr('r', r + 3).attr('fill', col).attr('opacity', 0.18);
      g.append('circle').attr('cx', x).attr('cy', y).attr('r', r)
        .attr('fill', col).attr('stroke', '#fff').attr('stroke-width', 1.5);
      if (e.label) {
        var lblY = e._yOff <= 0 ? y - r - 6 : y + r + 13;
        var lblShort = e.label.length > 30 ? e.label.slice(0, 29) + '…' : e.label;
        g.append('text')
          .attr('x', x).attr('y', lblY).attr('text-anchor', 'middle')
          .attr('font-size', 10).attr('fill', 'var(--text,#333)').attr('font-weight', 500)
          .text(lblShort);
      }
      g.on('mouseenter', function(ev) {
        var html = '<div style="font-weight:600;margin-bottom:4px">' + escapeHtml(e.label || '(unlabeled)') + '</div>' +
          '<div style="opacity:0.75;font-size:11px;margin-bottom:6px">' +
            escapeHtml(e.actor) + ' · ' + escapeHtml(fmtTime(e.time)) +
            (e.category ? ' · ' + escapeHtml(e.category) : '') +
          '</div>' +
          (e.message ? '<div style="border-top:1px solid rgba(255,255,255,0.18);padding-top:6px;">' + escapeHtml(e.message) + '</div>' : '');
        tip.innerHTML = html;
        tip.style.display = 'block';
        tip.style.left = (ev.clientX + 14) + 'px';
        tip.style.top = (ev.clientY + 14) + 'px';
      });
      g.on('mousemove', function(ev) {
        tip.style.left = (ev.clientX + 14) + 'px';
        tip.style.top = (ev.clientY + 14) + 'px';
      });
      g.on('mouseleave', function() { tip.style.display = 'none'; });
    });

    var zoom = d3.zoom().scaleExtent([0.5, 10])
      .translateExtent([[-W, -H], [W * 2, H * 2]])
      .on('zoom', function(event) { root.attr('transform', event.transform); });
    svg.call(zoom);
    svg.on('dblclick.zoom', null);
    svg.on('dblclick', function() {
      svg.transition().duration(250).call(zoom.transform, d3.zoomIdentity);
    });
  };

  render();

  var obs = new MutationObserver(function() {
    if (!document.body.contains(wrap)) {
      if (tip && tip.parentNode) tip.parentNode.removeChild(tip);
      obs.disconnect();
    }
  });
  obs.observe(document.body, { childList: true, subtree: true });
}
